using UnityEngine;
using System.Collections.Generic;

[System.Serializable]
public class SaveData
{
    public int score;
    public int lives;
    public int level;
    public float health;
    public float[] position;
    public List<string> inventory;
    public bool[] levelProgress;
    public string saveTime;
}

public class SaveSystemChallenge : MonoBehaviour
{
    private const string SAVE_KEY = "GameSave";

    // References to game systems
    public PlayerHealth playerHealth;
    public ScoreManager scoreManager;
    public LevelManager levelManager;
    public InventorySystem inventorySystem;
    public Transform playerTransform;

    void Update()
    {
        // Quick save and load
        if (Input.GetKeyDown(KeyCode.F5))
        {
            SaveGame();
        }
        if (Input.GetKeyDown(KeyCode.F9))
        {
            LoadGame();
        }
    }

    public void SaveGame()
    {
        SaveData data = new SaveData();

        // Collect data from all systems
        data.score = scoreManager.GetScore();
        data.lives = scoreManager.GetLives();
        data.level = levelManager.GetCurrentLevel();
        data.health = playerHealth.GetHealth();
        data.position = new float[] {
            playerTransform.position.x,
            playerTransform.position.y,
            playerTransform.position.z
        };
        data.inventory = inventorySystem.GetItems();
        data.levelProgress = levelManager.GetLevelProgress();
        data.saveTime = System.DateTime.Now.ToString();

        // Serialize and save
        string json = JsonUtility.ToJson(data, true);
        PlayerPrefs.SetString(SAVE_KEY, json);
        PlayerPrefs.Save();

        Debug.Log("✅ Game saved!");
        Debug.Log("Score: " + data.score);
        Debug.Log("Level: " + data.level);
        Debug.Log("Saved at: " + data.saveTime);
    }

    public void LoadGame()
    {
        if (!PlayerPrefs.HasKey(SAVE_KEY))
        {
            Debug.Log("❌ No save data found!");
            return;
        }

        string json = PlayerPrefs.GetString(SAVE_KEY);
        SaveData data = JsonUtility.FromJson<SaveData>(json);

        if (data == null)
        {
            Debug.LogError("❌ Failed to load save data!");
            return;
        }

        // Apply data to all systems
        scoreManager.SetScore(data.score);
        scoreManager.SetLives(data.lives);
        levelManager.SetCurrentLevel(data.level);
        playerHealth.SetHealth(data.health);
        playerTransform.position = new Vector3(data.position[0], data.position[1], data.position[2]);
        inventorySystem.SetItems(data.inventory);
        levelManager.SetLevelProgress(data.levelProgress);

        Debug.Log("✅ Game loaded!");
        Debug.Log("Score: " + data.score);
        Debug.Log("Level: " + data.level);
        Debug.Log("Saved at: " + data.saveTime);
    }

    public void DeleteSave()
    {
        PlayerPrefs.DeleteKey(SAVE_KEY);
        Debug.Log("🗑️ Save data deleted!");
    }

    public bool HasSave()
    {
        return PlayerPrefs.HasKey(SAVE_KEY);
    }
}

// Example systems (placeholder classes)
public class PlayerHealth : MonoBehaviour
{
    private float health = 100f;

    public float GetHealth() => health;
    public void SetHealth(float value) => health = value;
}

public class ScoreManager : MonoBehaviour
{
    private int score = 0;
    private int lives = 3;

    public int GetScore() => score;
    public void SetScore(int value) => score = value;
    public int GetLives() => lives;
    public void SetLives(int value) => lives = value;
}

public class LevelManager : MonoBehaviour
{
    private int currentLevel = 1;
    private bool[] levelProgress = new bool[10];

    public int GetCurrentLevel() => currentLevel;
    public void SetCurrentLevel(int level) => currentLevel = level;
    public bool[] GetLevelProgress() => levelProgress;
    public void SetLevelProgress(bool[] progress) => levelProgress = progress;
}

public class InventorySystem : MonoBehaviour
{
    private List<string> items = new List<string>();

    public List<string> GetItems() => items;
    public void SetItems(List<string> newItems) => items = newItems;
}

public class ChallengeSummary : MonoBehaviour
{
    void Start()
    {
        Debug.Log("=== Mini Challenge — Add Save System ===");
        Debug.Log("✅ Save game data (F5)");
        Debug.Log("✅ Load game data (F9)");
        Debug.Log("✅ Save: score, lives, level, health, position, inventory, progress");
        Debug.Log("✅ Load: all saved data");
        Debug.Log("🎯 Bonus: Add multiple save slots");
    }
}

