using UnityEngine;

public class SaveChallengeError : MonoBehaviour
{
    void Start()
    {
        // Forgetting to check if JSON is valid
        string json = "";
        SaveData data = JsonUtility.FromJson<SaveData>(json);  // Returns null

        // Using null data
        Debug.Log(data.score);  // NullReferenceException!
    }
}

phase2.explanation:
Invalid or empty JSON results in null. You need to check for null before using the data.

**The fix:**
```csharp
if (data != null)
{
    Debug.Log(data.score);
}
else
{
    Debug.LogError("Failed to load data!");
}
```

**Sharp-chan says:**
"Always check if deserialized data is null before using it."
